55	const PROCESSING_FEE = 5;
56	const DEDUCTIBLE = 100;
57	const CAP_MULTIPLIER = 2;
58	
59	const BASE_PREMIUM: Record<string, number> = {
60	  sword: 100,
61	  amulet: 60,
62	  staff: 80,
63	  potion: 40,
64	  rune: 25,
65	  moonstone: 25,
66	};
67	
68	const INSURANCE_VALUE: Record<string, number> = {
69	  sword: 1000,
70	  amulet: 600,
71	  staff: 800,
72	  potion: 400,
73	  rune: 250,
74	  moonstone: 250,
75	};
76	
77	const CURSED_SURCHARGE_RATE = 0.5;
78	const HIGH_ENCHANTMENT_THRESHOLD = 5;
79	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
80	const FIRST_INSURANCE_RATE = 0.1;
81	const LOYALTY_THRESHOLD_YEARS = 2;
82	const LOYALTY_DISCOUNT_RATE = 0.2;
83	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
84	
85	const isCursed = (item: Item): boolean => item.cursed === true;
86	const isHighlyEnchanted = (item: Item): boolean =>
87	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
88	
89	const surchargeRate = (item: Item): number =>
90	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
91	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
92	
93	const itemBaseValue = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
94	
95	const itemSurcharge = (item: Item): number =>
96	  itemBaseValue(item) * surchargeRate(item);
97	
98	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
99	const BLOCK_SIZE = 3;
100	const BLOCK_PREMIUM = 60;
101	
102	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
103	
104	const sumBy = <T>(values: T[], measure: (value: T) => number): number =>
105	  values.reduce((sum, value) => sum + measure(value), 0);
106	
107	const groupByType = (items: Item[]): Item[][] => {
108	  const byType = new Map<string, Item[]>();
109	  for (const item of items) {
110	    const group = byType.get(item.type) ?? [];
111	    group.push(item);
112	    byType.set(item.type, group);
113	  }
114	  return [...byType.values()];
115	};
116	
117	const groupPremium = (group: Item[]): number =>
118	  group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumBy(group, itemBaseValue);
119	
120	const partition = <T>(values: T[], predicate: (value: T) => boolean): [T[], T[]] => {
121	  const matches: T[] = [];
122	  const rest: T[] = [];
123	  for (const value of values) {
124	    (predicate(value) ? matches : rest).push(value);
125	  }
126	  return [matches, rest];
127	};
128	
129	const policyBasePremium = (items: Item[]): number => {
130	  const [components, mainItems] = partition(items, isComponent);
131	  return sumBy(groupByType(components), groupPremium) + sumBy(mainItems, itemBaseValue);
132	};
133	
134	const totalSurcharges = (items: Item[]): number => sumBy(items, itemSurcharge);
135	
136	const loyaltyRate = (customer: Customer): number =>
137	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0;
138	
139	const followUpRate = (isFollowUp: boolean): number =>
140	  isFollowUp ? FOLLOW_UP_DISCOUNT_RATE : 0;
141	
142	const netPolicyRate = (customer: Customer, isFollowUp: boolean): number =>
143	  FIRST_INSURANCE_RATE - loyaltyRate(customer) - followUpRate(isFollowUp);
144	
145	const quotePremium = (customer: Customer, items: Item[], isFollowUp: boolean): number => {
146	  const base = policyBasePremium(items);
147	  const surcharges = totalSurcharges(items);
148	  const policyAdjustment = base * netPolicyRate(customer, isFollowUp);
149	  return Math.ceil(base + surcharges + policyAdjustment + PROCESSING_FEE);
150	};
151	
152	interface Policy {
153	  items: Item[];
154	  insuranceSum: number;
155	  remainingCap: number;
156	}
157	
158	const insuranceSum = (items: Item[]): number =>
159	  sumBy(items, (item) => INSURANCE_VALUE[item.type] ?? 0);
160	
161	const newPolicy = (items: Item[]): Policy => {
162	  const sum = insuranceSum(items);
163	  return { items, insuranceSum: sum, remainingCap: sum * CAP_MULTIPLIER };
164	};
165	
166	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
167	  const damage = incident.damages[0];
168	  const reimbursable = damage.amount - DEDUCTIBLE;
169	  const payout = Math.min(reimbursable, policy.remainingCap);
170	  policy.remainingCap -= payout;
171	  return { payout, remainingCap: policy.remainingCap };
172	};
173	
174	export const runScenario = (scenario: Scenario): ScenarioResult => {
175	  let quoteCount = 0;
176	  const policies: Record<number, Policy> = {};
177	  const results = scenario.steps.map((step, index): StepResult => {
178	    if (step.op === "quote") {
179	      const isFollowUp = quoteCount > 0;
180	      quoteCount += 1;
181	      policies[index] = newPolicy(step.items);
182	      return { premium: quotePremium(scenario.customer, step.items, isFollowUp) };
183	    }
184	    return processClaim(policies[step.policy], step.incident);
185	  });
186	  return { results };
187	};
